// Normalize and identify sender
let ip = msg.url.split("/")[2].split(":")[0];
let response = (msg.payload || "").toString().toLowerCase();

// List of expected Pi IPs
let expected = [/*"192.168.1.11",*//* "192.168.1.12",*/ "192.168.1.13"/*, "192.168.1.14"*/];

// Get or initialize tracker
let status = flow.get("videoLoadStatus") || {};

// Use simple heuristic to check if the Pi is "ready"
if (
    response.includes("paused") ||
    response.includes("loaded") ||
    response.includes("ok") ||
    response.includes("ready")
) {
    status[ip] = true;
    node.status({fill:"green",shape:"dot",text:`${ip} ready`});
} else {
    status[ip] = false;
    node.status({fill:"red",shape:"ring",text:`${ip} not ready`});
}

flow.set("videoLoadStatus", status);

// Check if all 4 are ready
let allReady = expected.every(ip => status[ip]);

if (allReady) {
    // Reset for next round
    flow.set("videoLoadStatus", {});
    msg.payload = "ALL_READY";
    return [msg, null];  // Continue flow
} else {
    return [null, null]; // Wait
}

